class Solution:
    def preorder(self, root):
        if root is None:
            return []
        result = [root.val]
        stack = [(root, 0)]
        while stack:
            node, idx = stack[-1]
            children = node.children or []
            if idx < len(children):
                stack[-1] = (node, idx + 1)
                child = children[idx]
                result.append(child.val)
                stack.append((child, 0))
            else:
                stack.pop()
        return result

